{"code": "import json
import re
from collections import defaultdict

# Load the data
reviews = locals()['var_functions.query_db:16']
businesses = locals()['var_functions.query_db:18']

# Create business map: numeric_id -> business info
business_map = {}
for biz in businesses:
    biz_id = biz['business_id']
    match = re.match(r'businessid_(\d+)', biz_id)
    if match:
        numeric_id = match.group(1)
        business_map[numeric_id] = biz

# Count reviews per category
category_review_counts = defaultdict(int)
processed_reviews = 0
no_description = 0
invalid_business_ref = 0
no_categories_found = 0

for review in reviews:
    business_ref = review['business_ref']

    # Extract numeric part from business_ref (e.g., businessref_21 -> 21)
    match = re.match(r'businessref_(\d+)', business_ref)
    if not match:
        invalid_business_ref += 1
        continue

    numeric_id = match.group(1)

    # Get business info
    if numeric_id not in business_map:
        invalid_business_ref += 1
        continue

    biz = business_map[numeric_id]
    description = biz.get('description', '')

    if not description:
        no_description += 1
        continue

    # Extract categories from description
    categories = []

    # Pattern 1: "services in X, Y, and Z"
    pattern1_matches = re.findall(r'(?:services|fields) in ([^\.\n]+)', description, re.IGNORECASE)
    for match_text in pattern1_matches:
        # Split by commas and 'and'
        parts = re.split(r', | and ', match_text)
        for part in parts:
            part = part.strip().rstrip('.')
            if part and part != 'and more' and len(part) > 2:
                categories.append(part)

    # Pattern 2: "including X, Y, and Z"
    if not categories:
        pattern2_matches = re.findall(r'including ([^\.\n]+)', description, re.IGNORECASE)
        for match_text in pattern2_matches:
            parts = re.split(r', |,', match_text)
            for part in parts:
                part = part.strip().rstrip('.')
                if part and part != 'and more' and ' and ' not in part:
                    if part:
                        categories.append(part)
                elif ' and ' in part:
                    # Handle "X and Y" case
                    subparts = part.split(' and ')
                    for subpart in subparts:
                        subpart = subpart.strip()
                        if subpart and subpart != 'more':
                            categories.append(subpart)

    # Pattern 3: "in the fields of X, Y, and Z"
    if not categories:
        pattern3_matches = re.findall(r'in the fields of ([^\.\n]+)', description, re.IGNORECASE)
        for match_text in pattern3_matches:
            parts = re.split(r', | and ', match_text)
            for part in parts:
                part = part.strip().rstrip('.')
                if part and part != 'and more' and len(part) > 2:
                    categories.append(part)

    processed_reviews += 1

    if categories:
        for category in categories:
            category_review_counts[category] += 1
    else:
        no_categories_found += 1

# Get top 5 categories
top_5_categories = sorted(category_review_counts.items(), key=lambda x: x[1], reverse=True)[:5]

# Prepare output
result = {
    'total_reviews_by_2016_users': len(reviews),
    'processed_reviews': processed_reviews,
    'invalid_business_references': invalid_business_ref,
    'no_description': no_description,
    'no_categories_extracted': no_categories_found,
    'top_5_categories': top_5_categories
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

